const https = require('https');

function httpReq(url, options = {}) {
  return new Promise((resolve, reject) => {
    const m = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!m) { reject(new Error('Invalid URL: ' + url)); return; }
    const hostname = m[1];
    const path = m[2] || '/';
    const postData = options.body || '';
    const req = https.request({
      hostname: hostname,
      port: 443,
      path: path,
      method: options.method || 'GET',
      headers: { ...options.headers, ...(postData ? { 'Content-Length': Buffer.byteLength(postData) } : {}) }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString();
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, text: () => Promise.resolve(body), json: () => Promise.resolve(JSON.parse(body)), headers: res.headers });
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('Request timeout')); });
    if (postData) req.write(postData);
    req.end();
  });
}

const SUPABASE_URL = 'https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q';
const sbHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

const input = $input.first().json;
const { body } = input;

if (!body || !body.token) {
  return [{ json: { success: false, error: 'Token is required' } }];
}

if (!body.vendor_id) {
  return [{ json: { success: false, error: 'vendor_id is required' } }];
}

try {
  // 1. Verify auth token
  const authResp = await httpReq('https://api.katalync.com/webhook/auth-verify', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token: body.token })
  });
  const authData = await authResp.json();
  if (!authData.success) {
    return [{ json: { success: false, error: authData.error || 'Token invalid or expired' } }];
  }

  // 2. Upsert user
  const upsertResp = await httpReq(SUPABASE_URL + '/users?on_conflict=email', {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'resolution=merge-duplicates,return=representation' },
    body: JSON.stringify([{
      email: authData.email,
      name: authData.name || authData.email,
      password_hash: 'oauth-managed',
      role: authData.role || 'user',
      company: authData.company || null,
      lang: authData.lang || 'es',
      onboarded: authData.onboarded || false,
      subscription_status: authData.subscription_status || 'active',
      last_login_at: new Date().toISOString()
    }])
  });
  const upsertData = await upsertResp.json();
  const user_id = upsertData && upsertData.length > 0 ? upsertData[0].id : null;
  if (!user_id) {
    return [{ json: { success: false, error: 'Failed to provision user' } }];
  }

  // 3. Verify vendor belongs to this user
  const ownerResp = await httpReq(SUPABASE_URL + '/vendors?id=eq.' + body.vendor_id + '&user_id=eq.' + user_id, {
    method: 'GET',
    headers: sbHeaders
  });
  const ownerData = await ownerResp.json();
  if (!Array.isArray(ownerData) || ownerData.length === 0) {
    return [{ json: { success: false, error: 'Vendor not found or access denied' } }];
  }

  // 4. Build update object from only non-undefined fields
  const allowedFields = ['name', 'source', 'source_url', 'source_api_key', 'source_api_secret', 'company', 'marketplace_id', 'marketplace_api_key', 'marketplace_url', 'sync_interval_hours', 'sync_status'];
  const updateData = {};
  for (const field of allowedFields) {
    if (body[field] !== undefined) {
      updateData[field] = body[field];
    }
  }

  if (body.marketplaces) { const ec = ownerData[0].config || {}; updateData.config = { ...ec, marketplaces: body.marketplaces }; }

  if (Object.keys(updateData).length === 0) {
    return [{ json: { success: false, error: 'No fields to update' } }];
  }

  updateData.updated_at = new Date().toISOString();

  // 5. PATCH the vendor
  const patchResp = await httpReq(SUPABASE_URL + '/vendors?id=eq.' + body.vendor_id, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify(updateData)
  });
  const patchData = await patchResp.json();
  const updatedVendor = Array.isArray(patchData) && patchData.length > 0 ? patchData[0] : patchData;

  if (!patchResp.ok) {
    return [{ json: { success: false, error: 'Failed to update vendor: HTTP ' + patchResp.status } }];
  }

  // 6. Return success
  return [{ json: { success: true, vendor: updatedVendor } }];
} catch (e) {
  return [{ json: { success: false, error: 'Server error: ' + e.message } }];
}
